#[tokio::test]
async fn test_ws_upgrade_handshake() {
    // Tests WebSocket upgrade returns 101 Switching Protocols with correct Sec-WebSocket-Accept header
    let expected_body = r#""#.to_string();
    let mut app = spikard::App::new();
    app.route(spikard::get("/ws"), move |_ctx: spikard::RequestContext| {
        let body = expected_body.clone();
        async move {
            Ok(axum::http::Response::builder()
                .status(101u16)
                .header("content-type", "application/json")
                .body(axum::body::Body::from(body))
                .unwrap())
        }
    })
    .unwrap();
    let router = app.into_router().unwrap();
    let server = axum_test::TestServer::new(router);
    let response = server
        .get("/ws")
        .add_header(r#"Sec-WebSocket-Key"#, r#"dGhlIHNhbXBsZSBub25jZQ=="#)
        .add_header(r#"Sec-WebSocket-Version"#, r#"13"#)
        .add_header(r#"Connection"#, r#"Upgrade"#)
        .add_header(r#"Upgrade"#, r#"websocket"#)
        .await;
    assert_eq!(response.status_code().as_u16(), 101u16);
}
